    // We search for the smallest i starting from 0.
    // We only need to check up to the middle index (inclusive for odd length strings), 
    // because any larger i would correspond to a pair already checked with a smaller index j < i.
    const limit = Math.floor((n - 1) / 2);

    for (let i = 0; i <= limit; i++) {
        const j = n - 1 - i;
        if (s[i] === s[j]) {
            return i;
        }
    }

    // If no such index is found
    return -1;
}

